/* VAC bill formats — A4 skin (slate & cream, matches the VAC desk theme).
   Mechanics preserved from the Busy-replica build: table-layout fixed,
   percent widths on first-row cells, filler-row heights f-tall/f-mid.
   All band colors need print-color-adjust to survive PDF. */
.vac-bill { font-family: Arial, Helvetica, sans-serif; font-size: 9.5pt; color: #2f2e2a;
            -webkit-print-color-adjust: exact; print-color-adjust: exact; }
.vac-bill * { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
.vac-bill .bold { font-weight: bold; }
.vac-bill .bill-border { border: 1.5px solid #3e5d6e; border-radius: 10px; overflow: hidden; }
.vac-bill table { border-collapse: collapse; width: 100%; }
.vac-bill td, .vac-bill th { vertical-align: top; }

/* header */
.vac-bill .hdr { background: #faf9f5; border-bottom: 1.5px solid #3e5d6e; padding: 0 0 8px; }
.vac-bill .hdr-title { background: #3e5d6e; color: #fff; text-align: center; position: relative;
                       padding: 4px 10px; margin-bottom: 8px; }
.vac-bill .doc-title { font-weight: bold; font-size: 11.5pt; letter-spacing: 3px; }
.vac-bill .copy-label { position: absolute; right: 10px; top: 5px; font-size: 8.5pt; color: #dcebf2; white-space: nowrap; }
.vac-bill .hdr-tbl { table-layout: fixed; }
.vac-bill .hdr-tbl td { border: none; padding: 0 10px; }
.vac-bill .hdr-left { width: 46%; font-size: 9pt; line-height: 1.35; color: #535148; }
.vac-bill .co-name { font-size: 16.5pt; font-weight: bold; letter-spacing: 0.3px; white-space: nowrap;
                     color: #3e5d6e; margin-bottom: 1px; }
.vac-bill .hdr-left .bold { color: #2f2e2a; }
.vac-bill .hdr-tbl > tbody > tr > td { vertical-align: middle; }
.vac-bill .hdr-logo { width: 16%; text-align: center; }
.vac-bill .hdr-logo img { width: 78px; height: 78px; object-fit: contain; }
.vac-bill .hdr-lic { width: 38%; }
.vac-bill .lic-tbl { margin-top: 0; table-layout: fixed; width: 100%; background: #fff;
                     border: 1px solid #cbe0ea; border-radius: 6px; }
.vac-bill .lic-tbl td { border: none; font-size: 8.5pt; padding: 3.5px 8px; white-space: nowrap; }
.vac-bill .lic-tbl tr + tr td { border-top: 1px solid #eef3f6; }
.vac-bill .lic-key { width: 33%; color: #547788; font-weight: bold; letter-spacing: 0.3px; }
.vac-bill .lic-val { width: 67%; text-align: right; color: #2f2e2a; font-weight: bold; letter-spacing: 0.2px; }

/* party / meta */
.vac-bill .party-tbl { border-bottom: 1.5px solid #3e5d6e; table-layout: fixed; }
.vac-bill .party-tbl > tbody > tr > td { border: none; padding: 6px 10px 8px; }
.vac-bill .party-left { width: 55%; line-height: 1.4; }
.vac-bill .party-left > .bold { color: #547788; font-size: 8.5pt; text-transform: uppercase; letter-spacing: 1px; }
.vac-bill .party-name { font-weight: bold; font-size: 11pt; color: #2f2e2a; }
.vac-bill .party-gstin { margin-top: 4px; color: #535148; }
.vac-bill .party-right { width: 45%; background: #eff4fb; border-left: 1px solid #cbe0ea; }
.vac-bill .meta-line { padding: 1.5px 0; text-align: left; }
.vac-bill .meta-line > span:first-child, .vac-bill .meta-line > b { display: inline-block; }
.vac-bill .meta-line > span:first-child { width: 46%; text-align: right; padding-right: 8px; color: #547788; }

/* items */
.vac-bill .items-tbl { table-layout: fixed; }
.vac-bill .items-tbl th { background: #3e5d6e; color: #fff; border-right: 1px solid #547788;
                          font-size: 8pt; text-align: left; padding: 3.5px 4px; letter-spacing: 0.3px; }
.vac-bill .items-tbl td { border-right: 1px solid #d7e3ea; padding: 3px 4px; font-size: 9pt; line-height: 1.3; }
.vac-bill .items-tbl th:last-child, .vac-bill .items-tbl td:last-child { border-right: none; }
.vac-bill .items-tbl tbody tr:nth-child(even):not(.filler-row) td { background: #f5f8fb; }
/* Column widths sum to 99.5%. c-damt/c-qty are sized for the WORST CASE TOTALS,
   not the line values: the totals row prints "%.2f" disc (worst -18333.00, 9 ch)
   and "%.3f" qty (worst 4373.000, 8 ch). At 7%/5.5% those right-aligned totals
   overflowed LEFT across the column border and physically overlapped each other
   -- a real bill printed "-9426.782420.000". 536 invoices carry both a non-zero
   disc total and qty >= 100, so this was not an edge case. The width came from
   c-prod/c-mfg, which wrap anyway (longest item_name 41 ch, longest mfg 49 ch). */
.vac-bill .c-sr   { width: 3.5%; color: #96948b; }
.vac-bill .c-prod { width: 21%; font-weight: bold; }
.vac-bill .c-pack { width: 8%;  font-weight: bold; }
.vac-bill .c-hsn  { width: 9.5%; }
.vac-bill .c-mfg  { width: 7.5%; font-size: 8pt; color: #535148; }
.vac-bill .c-list { width: 7.5%; }
.vac-bill .c-drate{ width: 6%; }
.vac-bill .c-damt { width: 9.5%; }
.vac-bill .c-qty  { width: 8.5%; }
.vac-bill .c-rate { width: 8%; }
.vac-bill .c-num  { text-align: right; white-space: nowrap; }
.vac-bill .c-amt  { width: 10.5%; text-align: right; font-weight: bold; white-space: nowrap; color: #3e5d6e; }
.vac-bill .chg-none td { border: none !important; }

/* purchase columns (PO / GRN / voucher / debit note).
   No LIST/DISC columns: purchases never carry a real discount_percentage and
   price_list_rate == rate on virtually every row, so they'd print noise. */
.vac-bill .pu-prod { width: 26%; font-weight: bold; }
.vac-bill .pu-pack { width: 8.5%; font-weight: bold; }
.vac-bill .pu-hsn  { width: 10%; }
.vac-bill .pu-mfg  { width: 13%; font-size: 8pt; color: #535148; }
.vac-bill .pu-qty  { width: 7%; }
.vac-bill .pu-rate { width: 9.5%; }
.vac-bill .pu-gst  { width: 6.5%; }
.vac-bill .pu-amt  { width: 16%; text-align: right; font-weight: bold; white-space: nowrap;
                     color: #3e5d6e; }
/* purchase GST summary carries IGST too (sales never does) — 6 cols, so narrower */
.vac-bill .tax-tbl.pu-tax { width: 80%; }
.vac-bill .tax-tbl.pu-tax td { width: 13%; }
.vac-bill .tax-tbl.pu-tax td:first-child { width: 9%; }
.vac-bill .tax-tbl.pu-tax .tax-fill { width: 20% !important; }
/* supplier-bill callout on the purchase voucher */
.vac-bill .src-note { padding: 5px 10px; background: #faf9f5; border-bottom: 1.5px solid #3e5d6e;
                      font-size: 8pt; color: #6d6a5f; font-style: italic; }

/* delivery-note columns (shared frame, goods-only table) */
.vac-bill .dn-prod { width: 40%; }
.vac-bill .dn-pack { width: 12%; }
.vac-bill .dn-hsn  { width: 14%; }
.vac-bill .dn-mfg  { width: 20%; }
.vac-bill .dn-qty  { width: 10.5%; }
.vac-bill .items-tbl td.c-num, .vac-bill .items-tbl td.c-hsn { font-weight: bold; }
.vac-bill .batch-line { font-size: 7.5pt; font-weight: normal; color: #547788; margin-top: 1px; }
.vac-bill .filler-row td { border-bottom: 1.5px solid #3e5d6e; background: #fff; }
.vac-bill .filler-row.f-tall td { height: 55mm; }
.vac-bill .filler-row.f-mid td { height: 18mm; }
.vac-bill .filler-row.f-none td { height: 0; }
.vac-bill .totals-row td { border-bottom: 1.5px solid #3e5d6e; padding: 3.5px 4px; text-align: right;
                           background: #eff4fb; }
.vac-bill .totals-row .no-right-border { border-right: none; }
.vac-bill .totals-row .no-left-border { border-left: none; }

/* charges */
.vac-bill .charges-tbl { border-bottom: 1px solid #cbe0ea; table-layout: fixed; }
.vac-bill .charges-tbl td { padding: 2.5px 10px; }
.vac-bill .chg-label { text-align: center; color: #535148; }
.vac-bill .chg-amt { width: 12%; text-align: right; border-left: 1px solid #cbe0ea; font-weight: bold; }

/* grand total */
.vac-bill .grand-tbl { background: #3e5d6e; table-layout: fixed; }
.vac-bill .grand-tbl td { padding: 5px 10px; border: none; color: #fff; }
.vac-bill .gt-label { text-align: right; font-size: 10pt; letter-spacing: 1px; }
/* 22% not 14%: lakh-scale totals with Indian digit grouping ("21,32,404.50",
   12 chars @13pt bold ~= 36mm) overflowed the 27mm cell and clipped the last
   digit. Purchases reach 21.3L and 26 sales invoices are over 1L. */
.vac-bill .gt-amt { width: 22%; text-align: right; font-weight: bold; font-size: 13pt; }

/* tax + words */
.vac-bill .tax-words { border-bottom: 1.5px solid #3e5d6e; padding: 4px 10px 7px; background: #faf9f5; }
.vac-bill .tax-tbl { width: 62%; table-layout: fixed; }
.vac-bill .tax-tbl td { border: none; padding: 2px 6px 2px 0; text-align: right; font-size: 8.5pt;
                        width: 13%; color: #535148; }
.vac-bill .tax-tbl td:first-child { text-align: left; width: 9%; }
.vac-bill .tax-head td { font-weight: bold; color: #3e5d6e; border-bottom: 1px solid #3e5d6e; }
.vac-bill .tax-fill { width: 35% !important; border-bottom: none !important; }
.vac-bill .words-line { margin-top: 5px; color: #2f2e2a; }
.vac-bill .words-label { font-size: 8pt; color: #547788; text-transform: uppercase; letter-spacing: 1px; }

/* payment pending (delivery slip / delivery note) */
.vac-bill .pending-wrap { padding: 6px 10px; border-bottom: 1.5px solid #3e5d6e; background: #faf9f5; }
.vac-bill .pending-box { width: 62mm; margin-left: auto; border: 1.2px solid #9a4b3c; border-radius: 8px;
                         overflow: hidden; background: #fff; }
.vac-bill .pending-box .pb-row { display: block; padding: 3px 8px; font-size: 9pt; }
.vac-bill .pending-box .pb-row span { display: inline-block; width: 60%; color: #535148; }
.vac-bill .pending-box .pb-row b { display: inline-block; width: 38%; text-align: right; }
.vac-bill .pending-box .pb-due { background: #9a4b3c; color: #fff; padding: 4px 8px; }
.vac-bill .pending-box .pb-due span { color: #f3ddd6; font-weight: bold; font-size: 8pt;
                                      text-transform: uppercase; letter-spacing: 0.5px; }
.vac-bill .pending-box .pb-due b { color: #fff; font-size: 11pt; }
.vac-bill .pending-paid { width: 62mm; margin-left: auto; border: 1.2px solid #4c7a4c; border-radius: 8px;
                          background: #eef5ee; color: #2f5d2f; text-align: center; font-weight: bold;
                          padding: 5px 8px; letter-spacing: 1px; }

/* signatures */
.vac-bill .sign-tbl { table-layout: fixed; background: #fff; }
.vac-bill .sign-tbl td { border: none; padding: 10px; }
.vac-bill .sign-left { width: 50%; color: #535148; }
.vac-bill .sign-right { text-align: right; font-size: 10.5pt; color: #3e5d6e; }

/* VAC bill formats — A5 compact skin (slate & cream, same design as A4).
   @page kept for the browser print dialog; PDF button follows global A4. */
@page { size: 148mm 210mm; }
