.vac-bill .meta-line { padding: 1px 0; text-align: left; }
.vac-bill .meta-line > span:first-child, .vac-bill .meta-line > b { display: inline-block; }
.vac-bill .meta-line > span:first-child { width: 46%; text-align: right; padding-right: 6px; color: #547788; }

/* items */
