.vac-bill .items-tbl th { background: #3e5d6e; color: #fff; border-right: 1px solid #547788;
                          font-size: 6.3pt; text-align: left; padding: 2.5px 3px; }
.vac-bill .items-tbl td { border-right: 1px solid #d7e3ea; padding: 2px 3px; font-size: 7.2pt; line-height: 1.25; }
.vac-bill .items-tbl th:last-child, .vac-bill .items-tbl td:last-child { border-right: none; }
.vac-bill .items-tbl tbody tr:nth-child(even):not(.filler-row) td { background: #f5f8fb; }
