.vac-bill .grand-tbl td { padding: 4px 8px; border: none; color: #fff; }
.vac-bill .gt-label { text-align: right; font-size: 8.5pt; letter-spacing: 1px; }
/* 26% not 16%: see the A4 note — lakh-scale totals clipped the last digit. */
