.vac-bill .tax-tbl { width: 70%; table-layout: fixed; }
.vac-bill .tax-tbl td { border: none; padding: 1.5px 5px 1.5px 0; text-align: right; font-size: 6.8pt;
                        width: 14%; color: #535148; }
.vac-bill .tax-tbl td:first-child { text-align: left; width: 9%; }
.vac-bill .tax-head td { font-weight: bold; color: #3e5d6e; border-bottom: 1px solid #3e5d6e; }
.vac-bill .tax-fill { width: 29% !important; border-bottom: none !important; }
.vac-bill .words-line { margin-top: 3px; color: #2f2e2a; }
.vac-bill .words-label { font-size: 6.5pt; color: #547788; text-transform: uppercase; letter-spacing: 0.8px; }

