.vac-rtgs .rtgs-foot td { vertical-align: bottom; padding: 2px 4px; }
.vac-rtgs .foot-left { width: 55%; line-height: 1.75; }
.vac-rtgs .foot-right { width: 45%; text-align: center; }
.vac-rtgs .sign-space { height: 42px; }
.vac-rtgs .sign-line { border-top: 1px solid #111; display: inline-block;
                       padding: 2px 26px 0; font-weight: bold; letter-spacing: 1px; }
.vac-rtgs .foot-right div:last-child { font-size: 9pt; }

/* tiny audit ref back to the voucher */
.vac-rtgs .rtgs-ref { text-align: right; font-size: 7.5pt; color: #777; margin-top: 6px; }

/* VAC Deposit Slip — monochrome BOI pay-in-slip skin (half-A4-ish content).
   Same conventions as vac_rtgs_neft.css: bank form, not a VAC bill; !important
   on cell paddings/line-heights because frappe's print.css forces its own. */
.vac-dep { font-family: Arial, Helvetica, sans-serif; font-size: 9.5pt; color: #111;
           line-height: 1.3;
           -webkit-print-color-adjust: exact; print-color-adjust: exact; }
.vac-dep .dep-frame { border: 1.5px solid #111; padding: 10px 16px 8px; }

/* header */
.vac-dep .dep-head-tbl { width: 100%; border-collapse: collapse; }
.vac-dep .dep-head-tbl td { vertical-align: top !important; padding: 0 !important; }
.vac-dep .dh-left { width: 55%; }
.vac-dep .dh-bank { font-weight: bold; font-size: 14pt; letter-spacing: 2px; }
.vac-dep .dh-branch { font-weight: bold; font-size: 9.5pt; letter-spacing: 2px; }
.vac-dep .dh-right { width: 45%; text-align: right; }
.vac-dep .dh-title { font-weight: bold; letter-spacing: 1.5px; border-bottom: 1px solid #111; }
.vac-dep .dh-date { display: inline-block; margin-top: 4px; }

/* account-type row + number boxes */
.vac-dep .dep-acct-row { margin-top: 8px; font-size: 8.5pt; letter-spacing: 0.4px; color: #333; }
.vac-dep .acct-pick { font-weight: bold; font-size: 10pt; color: #111;
                      border: 1.5px solid #111; border-radius: 8px; padding: 0 5px; }
.vac-dep .dep-boxes { margin: 4px 0 6px; }
.vac-dep .digit { display: inline-block; width: 22px; height: 22px; line-height: 22px !important;
                  border: 1px solid #111; border-right: none; text-align: center;
                  font-weight: bold; font-size: 11pt; }
.vac-dep .digit:last-child { border-right: 1px solid #111; }

/* name row */
.vac-dep .dep-name-tbl { width: 100%; border-collapse: collapse; margin-bottom: 4px; }
.vac-dep .dep-name-tbl td { vertical-align: bottom !important; padding: 3px 4px 1px !important;
                            line-height: 1.3 !important; }
.vac-dep .dep-name-tbl .lbl { width: 9%; white-space: nowrap; }
.vac-dep .dep-name-tbl .tel { width: 22%; }
.vac-dep .val { border-bottom: 1px dotted #555; font-weight: bold; }
.vac-dep .val.filled { border-bottom-color: transparent; }

/* body: left (words + cheques + total), right (cash denominations) */
.vac-dep .dep-body { width: 100%; border-collapse: collapse; }
.vac-dep .dep-body > tbody > tr > td { vertical-align: top !important; padding: 4px !important; }
.vac-dep .dep-left { width: 62%; }
.vac-dep .dep-right { width: 38%; }
.vac-dep .words-row .lbl { white-space: nowrap; }
.vac-dep .words-row .val { display: inline; }
.vac-dep .chq-tbl { width: 100%; border-collapse: collapse; margin-top: 8px; }
.vac-dep .chq-tbl th { background: #111; color: #fff; font-size: 8pt; text-align: left;
                       padding: 3px 6px !important; }
.vac-dep .chq-tbl td { border: 1px solid #444; padding: 7px 6px !important; }
.vac-dep .chq-rs { width: 18%; }
.vac-dep .chq-p { width: 8%; }
.vac-dep .pan-row { margin-top: 7px; font-size: 8.5pt; }
.vac-dep .total-row { margin-top: 9px; font-weight: bold; letter-spacing: 1px;
                      border: 1.5px solid #111; display: inline-block; padding: 5px 14px; }
.vac-dep .total-amt { font-size: 12pt; }
.vac-dep .ref-row { margin-top: 8px; font-size: 7.5pt; color: #777; }

/* cash denomination table */
.vac-dep .cash-tbl { width: 100%; border-collapse: collapse; }
.vac-dep .cash-tbl th { background: #111; color: #fff; font-size: 8pt; text-align: left;
                        padding: 3px 6px !important; }
.vac-dep .cash-tbl td { border: 1px solid #444; padding: 3px 6px !important;
                        line-height: 1.35 !important; }
.vac-dep .cash-tbl .cn { width: 32%; white-space: nowrap; }
.vac-dep .cash-tbl .cq { width: 22%; text-align: right; }
.vac-dep .cash-tbl .ca { width: 46%; text-align: right; }
.vac-dep .cash-total td { font-weight: bold; background: #eee; }

/* footer */
.vac-dep .dep-foot { width: 100%; border-collapse: collapse; margin-top: 6px; }
.vac-dep .dep-foot td { vertical-align: bottom !important; padding: 4px !important; }
.vac-dep .df-left { width: 50%; color: #333; }
.vac-dep .df-right { width: 50%; text-align: center; }
.vac-dep .sign-space { height: 34px; }
.vac-dep .sign-line { border-top: 1px solid #111; display: inline-block;
                      padding: 2px 20px 0; font-weight: bold; }
.vac-dep .df-co { font-size: 8.5pt; }

